"""Direct constructor for n=26 circle packing with optimized hexagonal pattern"""
import numpy as np

def construct_packing():
    """Place 26 circles in optimized positions based on hexagonal lattice pattern.
    Pattern: alternating rows of 5,4,5,4,5,3 circles for efficient packing.
    """
    n = 26
    centers = np.zeros((n, 2))
    idx = 0

    # Optimized hexagonal pattern: rows with alternating counts
    # Row offsets create hexagonal close-packing arrangement
    row_configs = [
        (5, 0.08, 0.10),    # 5 circles, y=0.08, x_start=0.10
        (4, 0.22, 0.175),   # 4 circles, y=0.22, x_start=0.175 (offset)
        (5, 0.36, 0.10),    # 5 circles
        (4, 0.50, 0.175),   # 4 circles (center row)
        (5, 0.64, 0.10),    # 5 circles
        (3, 0.78, 0.20),    # 3 circles, y=0.78
    ]

    x_spacing = 0.165  # Horizontal spacing between circles in same row

    for count, y, x_start in row_configs:
        for j in range(count):
            centers[idx] = [x_start + j * x_spacing, y]
            idx += 1

    radii = _compute_max_radii(centers)
    return centers, radii, np.sum(radii)


def _compute_max_radii(centers):
    """Compute maximum valid radii via iterative expansion and constraint satisfaction."""
    n = centers.shape[0]
    radii = np.array([min(c[0], c[1], 1-c[0], 1-c[1]) for c in centers])

    # Precompute distances for efficiency
    dist = np.zeros((n, n))
    for i in range(n):
        for j in range(i+1, n):
            dist[i, j] = dist[j, i] = np.linalg.norm(centers[i] - centers[j])

    # Iterative expansion phase
    for _ in range(500):
        changed = False
        for i in range(n):
            max_r = min(centers[i, 0], centers[i, 1], 1 - centers[i, 0], 1 - centers[i, 1])
            for j in range(n):
                if i != j:
                    max_r = min(max_r, dist[i, j] - radii[j])
            if max_r > radii[i] + 1e-10:
                radii[i] = max_r * 0.9999
                changed = True
        if not changed:
            break

    # Final validity pass
    for i in range(n):
        radii[i] = min(radii[i], centers[i, 0], centers[i, 1], 1 - centers[i, 0], 1 - centers[i, 1])

    for _ in range(50):
        ok = True
        for i in range(n):
            for j in range(i+1, n):
                if radii[i] + radii[j] > dist[i, j] + 1e-10:
                    scale = dist[i, j] / (radii[i] + radii[j]) * 0.9999
                    radii[i] *= scale
                    radii[j] *= scale
                    ok = False
        if ok:
            break

    return radii
